import java.util.*;
import static java.lang.System.out; 
class FullMoons {
 static int DAY_IM = 1000 * 60 * 60 * 24; 
 public static void main(String [] args) {
 Calendar c = Calendar.getInstance();
 c.set(2004,0,7,15,40); 
 long day1 = c.getTimeInMillis();
 for (int x = 0; x < 60; x++) {
