 }
 }

 public void go() { 

 getSongs(); 
 System.out.println(songList);
 Collections.sort(songList);
 System.out.println(songList);
 ArtistCompare artistCompare = new ArtistCompare(); 
 Collections.sort(songList, artistCompare);
 System.out.println(songList); 

 }

